- src/app/oauth/callback/page.tsx (rewrite)

## What to do
The callback page currently uses BrowserOAuthClient to process the OAuth callback client-side. Rewrite it to forward the callback params to the server-side handler.

### New flow
1. The OAuth authorization server redirects back to `/oauth/callback?code=...&state=...&iss=...`
2. The callback page reads the query params from the URL.
3. It forwards them to `GET /api/auth/callback-handler?code=...&state=...&iss=...` (pass all query params through).
4. The server processes the callback, exchanges the code for tokens, sets the session cookie, and returns `{ did }`.
5. The callback page then:
   - If in an iframe: posts `{ type: "oauth-callback-complete", sub: did }` to parent window.
   - If top-level: redirects to `/` with `window.location.replace("/")`.

```typescript
"use client"

import { useEffect, useState } from "react"

export default function OAuthCallbackPage() {
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let cancelled = false

    async function handleCallback() {
      try {
        // Forward all query params to the server-side callback handler
        const callbackUrl = `/api/auth/callback-handler${window.location.search}`
        const res = await fetch(callbackUrl)

        if (!res.ok) {
          const data = await res.json().catch(() => ({ error: "Callback failed" }))
          throw new Error(data.error || "Authentication failed")
        }

        const { did } = await res.json()
        if (cancelled) return

        const isInIframe = window.parent !== window

        if (isInIframe) {
          window.parent.postMessage(
            { type: "oauth-callback-complete", sub: did },
            window.location.origin
          )
        } else {
          window.location.replace("/")
        }
      } catch (err) {
        if (cancelled) return
        console.error("OAuth callback error:", err)
        setError(err instanceof Error ? err.message : "Authentication failed")
      }
    }

    handleCallback()
    return () => { cancelled = true }
  }, [])

  // Keep the same UI as before (error state and loading state)
  if (error) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[var(--color-off-white)]">
        <div className="text-center">
          <p className="text-sm text-error mb-4 font-mono">{error}</p>
          <a href="/" className="text-sm text-accent font-mono hover:text-deep transition-colors duration-150">
            Return to home
          </a>
        </div>
      </div>
    )
  }

  return (
    <div className="loading-screen">
      <div className="loading-screen__inner">
        <img
          src="/assets/certified_brandmark.svg"
          alt="Certified"
          className="loading-screen__logo"
        />
        <p className="mt-6 text-sm text-white/40 font-mono">Completing sign in...</p>
      </div>
    </div>
  )
}
```

## Do not
- Import from @atproto/oauth-client-browser
- Import getOAuthClient
- Process the OAuth code exchange client-side
- Change the visual appearance (keep the same loading screen and error UI)
